class _PigeonCodec extends StandardMessageCodec {
  const _PigeonCodec();
  @override
  void writeValue(WriteBuffer buffer, Object? value) {
    if (value is int) {
      buffer.putUint8(4);
      buffer.putInt64(value);
    }    else if (value is FeatureStatusMsg) {
      buffer.putUint8(129);
      writeValue(buffer, value.index);
    }    else if (value is BodyMeasurementTypeMsg) {
      buffer.putUint8(130);
      writeValue(buffer, value.index);
    }    else if (value is VitalsMeasurementTypeMsg) {
      buffer.putUint8(131);
      writeValue(buffer, value.index);
    }    else if (value is CaloriesBurnedSourceMsg) {
      buffer.putUint8(132);
      writeValue(buffer, value.index);
    }    else if (value is ExerciseRouteStatusMsg) {
      buffer.putUint8(133);
      writeValue(buffer, value.index);
    }    else if (value is PlannedExerciseCompletionKindMsg) {
      buffer.putUint8(134);
